ce' => 'Device', 'import' => 'Import', 'system' => 'System'] as $value => $label): ?><option value="<?= e($value); ?>" <?= (string) old('source', 'manual') === $value ? 'selected' : ''; ?>><?= e($label); ?></option><?php endforeach; ?></select></div><div class="col-md-6"><label class="form-label">Clock In</label><input type="datetime-local" name="clock_in_time" class="form-control" value="<?= e((string) old('clock_in_time')); ?>"></div><div class="col-md-6"><label class="form-label">Clock Out</label><input type="datetime-local" name="clock_out_time" class="form-control" value="<?= e((string) old('clock_out_time')); ?>"></div><div class="col-12"><label class="form-label">Remarks</label><textarea name="remarks" class="form-control" rows="3" maxlength="255"><?= e((string) old('remarks')); ?></textarea></div></div><button type="submit" class="btn btn-primary w-100 mt-4">Save Attendance Record</button></form></div></div>
